const triggerData = $('Trigger').first().json;
const jobs = Array.isArray(triggerData.jobs) ? triggerData.jobs : [];

const str = (v) => (v === undefined || v === null) ? '' : String(v).trim();

const toIsoDate = (v) => {
  if (!v) return '';
  const d = new Date(v);
  return isNaN(d.getTime()) ? '' : d.toISOString();
};

const toBool = (v) => {
  if (v === true) return true;
  if (v === false) return false;
  const s = String(v || '').toLowerCase().trim();
  return s === 'true' || s === 'yes' || s === '1';
};

const stripHtml = (s) => String(s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

const normalized = jobs.map(job => {
  const descHtml = str(job.description_html);
  const description = str(job.description) || stripHtml(descHtml);
  return {
    company: str(job.company),
    title: str(job.title),
    url: str(job.url),
    description_html: descHtml,
    description: description,
    location: str(job.location),
    remote: toBool(job.remote),
    salary_text: str(job.salary_text),
    employment_type: str(job.employment_type).toUpperCase(),
    source: str(job.source),
    posted_at: toIsoDate(job.posted_at)
  };
});

console.log(`[Normalize] Normalized ${normalized.length} jobs`);

return normalized.map(j => ({ json: j }));

const config = $('Trigger').first().json.config || {};
const jobs = $input.all().map(item => item.json);

const parseList = (val) => {
  if (!val) return [];
  return String(val).split(/[;,]/).map(s => s.trim().toLowerCase()).filter(Boolean);
};

// Canonical employment-type vocabulary. Sources emit different raw tokens:
//   greenhouse: usually empty
//   lever:      FULLTIMEEMPLOYEE / INTERNATIONALEOR / INTERNATIONALOFFICEENTITY / INTERN / CONTRACTOR
//   ashby:      FULLTIME / PARTTIME / CONTRACT / INTERN / TEMPORARY
//   jsearch:    FULLTIME / PARTTIME / CONTRACTOR / INTERN / TEMPORARY
// Fold both the config tokens and each job's employment_type to canonical before
// comparing. Unknown tokens return '' so the membership check skips them rather
// than silently dropping the job â€” sources change their taxonomy without notice.
const canonicalizeEmployment = (raw) => {
  const s = String(raw || '').toLowerCase().replace(/[\s_-]/g, '');
  if (!s) return '';
  if (s === 'fulltime' || s === 'fulltimeemployee' || s === 'permanent') return 'full_time';
  if (s === 'internationaleor' || s === 'internationalofficeentity') return 'full_time';
  if (s === 'parttime') return 'part_time';
  if (s === 'contract' || s === 'contractor' || s === 'contracttohire') return 'contract';
  if (s === 'intern' || s === 'internship') return 'internship';
  if (s === 'temporary' || s === 'temp') return 'temporary';
  return ''; // unknown token â€” let the job through; do not silently drop
};

const excludeCompanies = parseList(config.exclude_companies);
const employmentTypesConsidered = parseList(config.employment_type_considered).map(canonicalizeEmployment).filter(Boolean);
const freshnessHours = Number(config.search_window_hours) || 0;

const now = Date.now();
const freshnessMs = freshnessHours > 0 ? freshnessHours * 60 * 60 * 1000 : 0;

const dropped = {
  company_excluded: 0,
  too_old: 0,
  employment_type_mismatch: 0
};
const filtered = [];

for (const job of jobs) {
  const company = String(job.company || '').toLowerCase().trim();
  const postedAt = job.posted_at ? new Date(job.posted_at).getTime() : NaN;
  const employmentType = canonicalizeEmployment(job.employment_type);

  if (excludeCompanies.length && excludeCompanies.includes(company)) {
    dropped.company_excluded++;
    continue;
  }

  if (freshnessMs > 0 && !isNaN(postedAt) && (now - postedAt > freshnessMs)) {
    dropped.too_old++;
    continue;
  }

  if (employmentTypesConsidered.length && employmentType && !employmentTypesConsidered.includes(employmentType)) {
    dropped.employment_type_mismatch++;
    continue;
  }

  filtered.push(job);
}

console.log(`[Hard Filter] Input: ${jobs.length}, Output: ${filtered.length}`);
console.log(`[Hard Filter] Dropped: ${JSON.stringify(dropped)}`);

return filtered.map(j => ({ json: j }));

const triggerData = $('Trigger').first().json;
const existingUrls = Array.isArray(triggerData.existing_job_urls) ? triggerData.existing_job_urls : [];
const existingRoles = Array.isArray(triggerData.existing_job_roles) ? triggerData.existing_job_roles : [];

const items = $input.all();

const normalizeUrl = (url) => {
  if (!url) return '';
  return String(url).toLowerCase().replace(/\/$/, '').trim();
};

// company || title || YYYY-MM-DD (date only; undated -> trailing empty slot).
// MUST stay byte-identical to the same helper in Data Loader > Filter Jobs.
const roleKey = (company, title, postedAt) => {
  const norm = (s) => String(s || '').toLowerCase().replace(/\s+/g, ' ').trim();
  const c = norm(company);
  const t = norm(title);
  if (!c || !t) return '';
  let d = '';
  const s = String(postedAt || '').trim();
  if (s) {
    const m = s.match(/^(\d{4}-\d{2}-\d{2})/);
    if (m) d = m[1];
    else { const dt = new Date(s); d = isNaN(dt.getTime()) ? '' : dt.toISOString().slice(0, 10); }
  }
  return `${c}||${t}||${d}`;
};

const existingSet = new Set(existingUrls.map(normalizeUrl).filter(Boolean));
const existingRoleSet = new Set(existingRoles.filter(Boolean));
const seenUrls = new Set();
const seenRoles = new Set();

const deduped = [];
let droppedExisting = 0;
let droppedRoleExisting = 0;
let droppedBatchDup = 0;
let droppedRoleDup = 0;
let noUrlKept = 0;

for (const item of items) {
  const job = item.json;
  const url = normalizeUrl(job.url);
  const role = roleKey(job.company, job.title, job.posted_at);

  // already in the database (cross-run, by URL)
  if (url && existingSet.has(url)) {
    droppedExisting++;
    continue;
  }

  // same role already in the database (cross-run, by company+title+date)
  if (role && existingRoleSet.has(role)) {
    droppedRoleExisting++;
    continue;
  }

  // same URL seen earlier in this batch
  if (url && seenUrls.has(url)) {
    droppedBatchDup++;
    continue;
  }

  // same role seen earlier in this batch (multi-location collapse, same date)
  if (role && seenRoles.has(role)) {
    droppedRoleDup++;
    continue;
  }

  if (url) seenUrls.add(url);
  if (role) seenRoles.add(role);
  if (!url) noUrlKept++;
  deduped.push(item);
}

console.log(`[Dedup] Input: ${items.length}, Output: ${deduped.length}, Existing-URL: ${droppedExisting}, Existing-role: ${droppedRoleExisting}, Batch-URL: ${droppedBatchDup}, Batch-role: ${droppedRoleDup}, No-URL kept: ${noUrlKept}`);

return deduped;
